 1	import { FC, ReactNode } from 'react';
 2	
 3	import { Flex, FlexItem, Panel, Split, SplitItem, Text, Title } from '@patternfly/react-core';
 4	
 5	import ExternalLink from '../ExternalLink';
 6	
 7	const InstructionBlock: FC<{
 8	  img: string;
 9	  title: string;
10	  description: string;
11	  link1?: string;
12	  link1Text?: string;
13	  link2?: string;
14	  link2Text?: string;
15	  component?: ReactNode;
16	}> = function ({ img, title, description, link1, link1Text, link2, link2Text, component }) {
17	  return (
18	    <Panel variant="bordered">
19	      <Split hasGutter>
20	        <SplitItem>
21	          <img src={img} alt="Link tutorial" style={{ width: '200px' }} />
22	        </SplitItem>
23	
24	        <SplitItem isFilled style={{ width: '100%' }}>
25	          <Flex
26	            direction={{ default: 'column' }}
27	            justifyContent={{ default: 'justifyContentCenter' }}
28	            style={{ height: '100%' }}
29	          >
30	            <FlexItem>
31	              <Title headingLevel="h3">{title}</Title>
32	            </FlexItem>
33	            <FlexItem>
34	              <Text>{description}</Text>
35	            </FlexItem>
36	
37	            <FlexItem>
38	              <small>
39	                {link1 && link1Text && <ExternalLink href={link1} text={link1Text} />}
40	                {link2 && link2Text && (
41	                  <>
42	                    <span className="pf-v5-u-mx-md"> | </span>
43	                    <ExternalLink href={link2} text={link2Text} />
44	                  </>
45	                )}
46	              </small>
47	            </FlexItem>
48	
49	            <FlexItem>{component}</FlexItem>
50	          </Flex>
51	        </SplitItem>
52	      </Split>
53	    </Panel>
54	  );
55	};
56	
57	export default InstructionBlock;

